/// ---------------------------------------------------------------------
/// 1. HTTP OVERRIDES (ENTERPRISE REQUIREMENT FOR CPI)
/// Bypasses the Self-Signed Certificate generated by the CPI Service.
/// ---------------------------------------------------------------------
class CpiHttpverrides extends HttpOverrides {
  @override
  HttpClient createHttpClient(SecurityContext? context) {
    return super.createHttpClient(context)
      ..badCertificateCallback =
          (X509Certificate cert, String host, int port) => true;
  }
}

