  }
}

/// ---------------------------------------------------------------------
/// 2. CPI API SERVICE LAYER (Strict Documentation Adherence)
/// ---------------------------------------------------------------------
class CpiApiService {
  String baseUrl = 'https://localhost:5000';
  String? accessToken;

  // Hardcoded Client ID & Secret Base64 encoded as per CPI Documentation
  final String _basicAuthHeader =
      'OWExMTc5MzBiMzJmNDNjMDg0Nzc1NjM5ZmM4ZjY3Mjg6SzhSRXVaM2JueHNGcFNHUXBFeE00Q3RqQlRtR3dQV0Y=';

  Future<bool> authenticate(
    String ipAddress,
    String username,
    String password,
  ) async {
    baseUrl = 'https://$ipAddress:5000';
    final url = Uri.parse('$baseUrl/connect/token');
    try {
      final response = await http
          .post(
            url,
            headers: {
              'Accept': 'application/json',
              'Content-Type': 'application/x-www-form-urlencoded',
              'Authorization': 'Basic $_basicAuthHeader',
            },
            body:
                'grant_type=password&username=${Uri.encodeComponent(username)}&password=${Uri.encodeComponent(password)}',
          )
          .timeout(const Duration(seconds: 10));

      if (response.statusCode == 200) {
        accessToken = json.decode(response.body)['access_token'];
        return true;
      }
      return false;
    } catch (e) {
      debugPrint('Auth Error: $e');
      return false;
    }
  }

  // --- SYSTEM & DIAGNOSTICS ---
  Future<Map<String, dynamic>> getSystemStatus() async {
    final res = await http.get(
      Uri.parse('$baseUrl/api/SystemStatus'),
      headers: _authHeaders(),
    );
    if (res.statusCode == 200) return json.decode(res.body);
    throw Exception('Failed to fetch system status');
  }

  Future<Map<String, dynamic>> getSystemMessages() async {
    final res = await http.get(
      Uri.parse('$baseUrl/api/SystemStatus/Messages'),
      headers: _authHeaders(),
    );
    if (res.statusCode == 200) return json.decode(res.body);
    throw Exception('Failed to fetch messages');
  }

  Future<List<dynamic>> getDevices() async {
    final res = await http.get(
      Uri.parse('$baseUrl/api/PaymentDevices'),
      headers: _authHeaders(),
    );
    if (res.statusCode == 200) return json.decode(res.body);
    return [];
  }

  Future<List<dynamic>> getExchangeRates() async {
    final res = await http.get(
      Uri.parse('$baseUrl/api/Settings/ExchangeRateSettings'),
      headers: _authHeaders(),
    );
    if (res.statusCode == 200) return json.decode(res.body);
    return [];
  }

  // --- SESSIONS (SHIFTS) ---
  Future<Map<String, dynamic>?> getCurrentSession() async {
    final res = await http.get(
      Uri.parse('$baseUrl/api/Session/Current'),
      headers: _authHeaders(),
    );
    if (res.statusCode == 200 && res.body.isNotEmpty)
      return json.decode(res.body);
    return null;
  }

  Future<bool> startNewSession() async {
    final res = await http.post(
      Uri.parse('$baseUrl/api/Session'),
      headers: _authHeaders(),
    );
    return res.statusCode == 200 || res.statusCode == 201;
  }

  // --- TRANSACTIONS ---
  Future<String> startTransaction(
    String type,
    double amount,
    String currencyCode,
  ) async {
    // Map UI-friendly names to CPI API transactionType values
    // CPI uses "Dispense" for refunds/withdrawals, not "Refund"
    final String apiTransactionType = type == 'Refund' ? 'Dispense' : type;

    final int valueInBaseUnits = (amount * 100)
        .round(); // CPI expects base unit scaling
    final res = await http.post(
      Uri.parse('$baseUrl/api/Transactions'),
      headers: _authHeaders()..addAll({'Content-Type': 'application/json'}),
      body: json.encode({
        "currencyCode": currencyCode,
        "transactionType": apiTransactionType,
        "value": valueInBaseUnits,
      }),
    );

    if (res.statusCode == 200 || res.statusCode == 201) {
      final data = json.decode(res.body);
      return data is List ? data.first['transactionId'] : data['transactionId'];
    }
    throw Exception('Transaction Error: ${res.statusCode} - ${res.body}');
  }

  Future<Map<String, dynamic>> getTransactionDetails(String id) async {
    final res = await http.get(
      Uri.parse('$baseUrl/api/Transactions/$id'),
      headers: _authHeaders(),
    );
    if (res.statusCode == 200) return json.decode(res.body);
    throw Exception('Failed to fetch transaction');
  }

  Future<void> cancelTransaction(String id) async {
    await http.get(
      Uri.parse('$baseUrl/api/Transactions/action/$id/cancel'),
      headers: _authHeaders(),
    );
  }

  Future<void> endTransaction(String id) async {
    // Ends transaction but keeps inserted cash (Used for split payments or halting deposits)
    await http.get(
      Uri.parse('$baseUrl/api/Transactions/action/$id/end'),
      headers: _authHeaders(),
    );
  }

  /// Fetches dispensable denominations from all device recyclers.
  /// Returns a list of {value (in cents), qty} entries.
  Future<List<Map<String, int>>> getDispensableInventory() async {
    final devices = await getDevices();
    final Map<int, int> denomMap = {};
    for (final dev in devices) {
      final recyclers = dev['recyclers'];
      if (recyclers == null) continue;
      final content = recyclers is Map ? recyclers['content'] : recyclers;
      if (content is! List) continue;
      for (final recycler in content) {
        final contents = recycler['contents'];
        if (contents is! List) continue;
        for (final denom in contents) {
          final value = denom['value'] as int? ?? 0;
          final qty = denom['qty'] as int? ?? 0;
          if (value > 0 && qty > 0) {
            denomMap[value] = (denomMap[value] ?? 0) + qty;
          }
        }
      }
    }
    return denomMap.entries
        .map((e) => {'value': e.key, 'qty': e.value})
        .toList()
      ..sort((a, b) => b['value']!.compareTo(a['value']!));
  }

  Map<String, String> _authHeaders() => {
    'Authorization': 'Bearer $accessToken',
  };
}

/// Calculates whether a target amount (in cents) can be dispensed using
/// available denominations, and returns the breakdown if possible.
class DenominationCalculator {
  /// Returns a map of {denomination_value_cents: count} if the amount can
  /// be made from the available denominations, or null if impossible.
  static Map<int, int>? calculateBreakdown(
    int targetCents,
    List<Map<String, int>> inventory,
  ) {
    if (targetCents <= 0) return null;
    // Sort denominations largest-first for greedy + backtracking
    final sorted = List<Map<String, int>>.from(inventory)
      ..sort((a, b) => b['value']!.compareTo(a['value']!));

    final result = <int, int>{};
    final found = _backtrack(targetCents, sorted, 0, result);
    return found ? result : null;
  }

  static bool _backtrack(
    int remaining,
    List<Map<String, int>> denoms,
    int startIndex,
    Map<int, int> result,
  ) {
    if (remaining == 0) return true;
    if (remaining < 0 || startIndex >= denoms.length) return false;

    for (int i = startIndex; i < denoms.length; i++) {
      final denomValue = denoms[i]['value']!;
      final denomQty = denoms[i]['qty']!;
      if (denomValue > remaining || denomQty <= 0) continue;

      // Try using as many of this denomination as possible, then fewer
      final maxUsable = remaining ~/ denomValue;
      final useCount = maxUsable > denomQty ? denomQty : maxUsable;

      for (int count = useCount; count >= 1; count--) {
        result[denomValue] = count;
        // Reduce available qty for deeper recursion
        final reducedDenoms = denoms.map((d) {
          if (d['value'] == denomValue) {
            return {'value': d['value']!, 'qty': d['qty']! - count};
          }
          return Map<String, int>.from(d);
        }).toList();

        if (_backtrack(
          remaining - (denomValue * count),
          reducedDenoms,
          i + 1,
          result,
        )) {
          return true;
        }
        result.remove(denomValue);
      }
    }
    return false;
  }

  /// Converts a breakdown map into a human-readable string.
  static String formatBreakdown(Map<int, int> breakdown) {
    final parts = breakdown.entries
        .where((e) => e.value > 0)
        .map((e) => '${e.value}x ${(e.key / 100).toStringAsFixed(2)}')
        .toList();
    return parts.join(' + ');
  }
}

final cpiApi = CpiApiService();

/// ---------------------------------------------------------------------
/// 3. LOGIN SCREEN (Optimized for Landscape)
/// ---------------------------------------------------------------------
class CpiLoginScreen extends StatefulWidget {
  const CpiLoginScreen({Key? key}) : super(key: key);
  @override
  State<CpiLoginScreen> createState() => _CpiLoginScreenState();
}

class _CpiLoginScreenState extends State<CpiLoginScreen> {
  final _ipController   = TextEditingController(text: 'localhost');
  final _userController = TextEditingController(text: 'admin@cpi.com');
  final _passController = TextEditingController(text: 'Test0001');
  bool _isLoading = false;

  Future<void> _login() async {
    setState(() => _isLoading = true);
    final success = await cpiApi.authenticate(
      _ipController.text.trim(),
      _userController.text.trim(),
      _passController.text.trim(),
    );
    setState(() => _isLoading = false);

    if (success && mounted) {
      Navigator.pushReplacement(
        context,
        MaterialPageRoute(builder: (_) => const LaptopDashboardScreen()),
      );
    } else {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text(
            'Connessione fallita. Controlla IP, Nome utente e Password.',
          ),
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Row(
        children: [
          Expanded(
            flex: 5,
            child: Container(
              color: Theme.of(context).colorScheme.primary,
              child: const Center(
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    Icon(Icons.point_of_sale, size: 120, color: Colors.white),
                    SizedBox(height: 24),
                    Text(
                      'CPI Servizio Pagamenti POS',
                      style: TextStyle(
                        fontSize: 36,
                        fontWeight: FontWeight.bold,
                        color: Colors.white,
                      ),
                    ),
                    SizedBox(height: 16),
                    Text(
                      'Edizione Enterprise v4.0',
                      style: TextStyle(fontSize: 18, color: Colors.white70),
                    ),
                  ],
                ),
              ),
            ),
          ),
          Expanded(
            flex: 4,
            child: Center(
              child: Container(
                constraints: const BoxConstraints(maxWidth: 450),
                padding: const EdgeInsets.all(48),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    const Text(
                      'Accedi',
                      style: TextStyle(
                        fontSize: 32,
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                    const SizedBox(height: 32),
                    TextField(
