/// ---------------------------------------------------------------------
/// 4. MAIN LAPTOP DASHBOARD (Sidebar + Main Content)
/// ---------------------------------------------------------------------
class LaptopDashboardScreen extends StatefulWidget {
  const LaptopDashboardScreen({Key? key}) : super(key: key);
  @override
  State<LaptopDashboardScreen> createState() => _LaptopDashboardScreenState();
}

class _LaptopDashboardScreenState extends State<LaptopDashboardScreen> {
  int _selectedIndex = 0;
  String _systemStatus = 'Checking...';
  String _sessionName = 'Loading Shift...';
  Timer? _pollingTimer;

  @override
  void initState() {
    super.initState();
    _fetchGlobalData();
    _pollingTimer = Timer.periodic(
      const Duration(seconds: 10),
      (_) => _fetchGlobalData(),
    );
  }

  @override
  void dispose() {
    _pollingTimer?.cancel();
    super.dispose();
  }

  Future<void> _fetchGlobalData() async {
    try {
      final status = await cpiApi.getSystemStatus();
      final session = await cpiApi.getCurrentSession();
      if (mounted) {
        setState(() {
          _systemStatus = status['currentStatus'] ?? 'Unknown';
          _sessionName = session != null
              ? session['sessionName']
              : 'No Active Shift';
        });
      }
    } catch (e) {
      // Background poll fail
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text(
          'CPI Terminale',
          style: TextStyle(fontWeight: FontWeight.bold, color: Colors.white),
        ),
        backgroundColor: Theme.of(context).colorScheme.primary,
        iconTheme: const IconThemeData(color: Colors.white),
        actions: [
          Chip(
            avatar: const Icon(Icons.work_history, size: 16),
            label: Text(_sessionName),
            backgroundColor: Colors.white,
          ),
          const SizedBox(width: 16),
          Chip(
            avatar: Icon(
              Icons.circle,
              size: 12,
              color: _systemStatus == 'IDLE' ? Colors.green : Colors.red,
            ),
            label: Text('Hardware: $_systemStatus'),
            backgroundColor: Colors.white,
          ),
          const SizedBox(width: 24),
        ],
      ),
      body: Row(
        children: [
          NavigationRail(
            selectedIndex: _selectedIndex,
            onDestinationSelected: (int index) =>
                setState(() => _selectedIndex = index),
            minExtendedWidth: 200,
            extended: true,
            backgroundColor: Colors.white,
            destinations: const [
              NavigationRailDestination(
                icon: Icon(Icons.point_of_sale_outlined),
                selectedIcon: Icon(Icons.point_of_sale),
                label: Text('Cassa'),
              ),
              NavigationRailDestination(
                icon: Icon(Icons.account_balance_wallet_outlined),
                selectedIcon: Icon(Icons.account_balance_wallet),
                label: Text('Gestione Cassa'),
              ),
              NavigationRailDestination(
                icon: Icon(Icons.devices_outlined),
                selectedIcon: Icon(Icons.devices),
                label: Text('Dispositivi'),
              ),
              NavigationRailDestination(
                icon: Icon(Icons.monitor_heart_outlined),
                selectedIcon: Icon(Icons.monitor_heart),
                label: Text('Diagnostica'),
              ),
              NavigationRailDestination(
                icon: Icon(Icons.work_outline),
                selectedIcon: Icon(Icons.work),
                label: Text('Turni'),
              ),
              NavigationRailDestination(
                icon: Icon(Icons.currency_exchange_outlined),
                selectedIcon: Icon(Icons.currency_exchange),
                label: Text('Tassi'),
              ),
            ],
          ),
          const VerticalDivider(thickness: 1, width: 1),
          Expanded(
            child: Container(
              color: Theme.of(context).colorScheme.background,
              child: _buildBody(),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildBody() {
    switch (_selectedIndex) {
      case 0:
        return const RegisterTab();
      case 1:
        return const CashManagementTab();
      case 2:
        return const DevicesTab();
      case 3:
        return const DiagnosticsTab();
      case 4:
        return const SessionsTab();
      case 5:
        return const ExchangeRatesTab();
      default:
        return const RegisterTab();
    }
  }
}

/// ---------------------------------------------------------------------
/// TAB 1: LAPTOP OPTIMIZED REGISTER (Cart Left + Numpad Right)
/// ---------------------------------------------------------------------
class RegisterTab extends StatefulWidget {
  const RegisterTab({Key? key}) : super(key: key);
  @override
  State<RegisterTab> createState() => _RegisterTabState();
}

class _RegisterTabState extends State<RegisterTab> {
  String _amountStr = '0.00';
  String _selectedCurrency = 'EUR';

  void _onNumpadTap(String val) {
    setState(() {
      if (val == 'C') {
        _amountStr = '0.00';
      } else {
        String cleanStr = _amountStr.replaceAll('.', '');
        cleanStr += val;
        int numericVal = int.parse(cleanStr);
        _amountStr = (numericVal / 100).toStringAsFixed(2);
      }
    });
  }

  void _startTransaction(String type) {
    final amount = double.tryParse(_amountStr) ?? 0.0;
    if (type != 'Accept' && amount <= 0) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Inserisci un importo maggiore di 0.')),
      );
      return;
    }
    showDialog(
      context: context,
      barrierDismissible: true,
      builder: (_) => CpiTransactionModal(
        transactionType: type,
        amount: amount,
        currencyCode: _selectedCurrency,
      ),
    ).then((_) => setState(() => _amountStr = '0.00'));
  }

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.all(24.0),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Left: Order Summary & Cart
          Expanded(
            flex: 5,
            child: Card(
              child: Padding(
                padding: const EdgeInsets.all(32.0),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    const Text(
                      'Ordine Corrente',
                      style: TextStyle(
                        fontSize: 28,
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                    const Divider(height: 32),
                    Expanded(
                      child: Center(
                        child: Column(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            const Text(
                              'Importo Dovuto',
                              style: TextStyle(
                                fontSize: 24,
                                color: Colors.grey,
                              ),
                            ),
                            const SizedBox(height: 16),
                            Text(
                              '$_selectedCurrency $_amountStr',
                              style: TextStyle(
                                fontSize: 72,
                                fontWeight: FontWeight.bold,
                                color: Theme.of(context).colorScheme.primary,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ),
                    const Divider(height: 32),
                    Row(
                      mainAxisAlignment: MainAxisAlignment.spaceBetween,
                      children: [
                        const Text(
                          'Valuta:',
