    );
  }
}

/// ---------------------------------------------------------------------
/// TAB 2: CASH MANAGEMENT (Floating, Emptying, Dispensing)
/// ---------------------------------------------------------------------
class CashManagementTab extends StatelessWidget {
  const CashManagementTab({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final ops = [
      {
        'title': 'Float verso Cassaforte',
        'type': 'FloatToCashBox',
        'icon': Icons.move_to_inbox,
        'desc': 'Sposta i fondi in eccesso oltre il float nella cassaforte.',
      },
      {
        'title': 'Float verso Erogazione',
        'type': 'FloatToDispense',
        'icon': Icons.output,
        'desc': 'Eroga manualmente i fondi in eccesso oltre il float.',
      },
      {
