/// ---------------------------------------------------------------------
/// TAB 3: DEVICES — Connected Hardware & Info
/// ---------------------------------------------------------------------
class DevicesTab extends StatefulWidget {
  const DevicesTab({Key? key}) : super(key: key);
  @override
  State<DevicesTab> createState() => _DevicesTabState();
}

class _DevicesTabState extends State<DevicesTab> {
  List<dynamic> _devices = [];
  bool _isLoading = false;
  int? _selectedIndex;

  @override
  void initState() {
    super.initState();
    _fetchDevices();
  }

  Future<void> _fetchDevices() async {
    setState(() => _isLoading = true);
    try {
      final devices = await cpiApi.getDevices();
      setState(() {
        _devices = devices;
        _isLoading = false;
      });
    } catch (e) {
      setState(() => _isLoading = false);
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Errore caricamento dispositivi: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

  IconData _deviceIcon(String? deviceName) {
    final name = (deviceName ?? '').toUpperCase();
    if (name.contains('BNR') || name.contains('BNF')) return Icons.money;
    if (name.contains('CCR') || name.contains('CR6000'))
      return Icons.rotate_right;
    if (name.contains('CLS')) return Icons.savings;
    if (name.contains('SCN')) return Icons.document_scanner;
    if (name.contains('SCR')) return Icons.swap_horiz;
    if (name.contains('BCR')) return Icons.toll;
    return Icons.memory;
  }

  Color _stateColor(String? state) {
    switch ((state ?? '').toLowerCase()) {
      case 'idle':
        return Colors.green;
      case 'busy':
        return Colors.blue;
      case 'error':
        return Colors.red;
      case 'initializing':
        return Colors.orange;
      case 'disconnected':
        return Colors.grey;
      case 'disabled':
        return Colors.grey.shade600;
      default:
        return Colors.grey;
    }
  }

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.all(24.0),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              const Text(
                'Dispositivi Collegati',
                style: TextStyle(fontSize: 28, fontWeight: FontWeight.bold),
              ),
              Row(
                children: [
                  Chip(
                    avatar: const Icon(Icons.devices, size: 16),
                    label: Text('${_devices.length} dispositivo/i'),
                    backgroundColor: Colors.white,
                  ),
                  const SizedBox(width: 12),
                  _isLoading
                      ? const SizedBox(
                          width: 24,
                          height: 24,
                          child: CircularProgressIndicator(strokeWidth: 2),
                        )
                      : IconButton(
                          onPressed: _fetchDevices,
                          icon: const Icon(Icons.refresh),
                          tooltip: 'Aggiorna',
                        ),
                ],
              ),
            ],
          ),
          const SizedBox(height: 8),
          const Text(
            'Visualizza le informazioni dettagliate di ogni dispositivo hardware collegato.',
            style: TextStyle(fontSize: 14, color: Colors.grey),
          ),
          const Divider(height: 24),
          Expanded(
            child: _devices.isEmpty
                ? Center(
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Icon(
                          Icons.devices_other,
                          size: 64,
                          color: Colors.grey.shade400,
                        ),
                        const SizedBox(height: 16),
                        Text(
                          _isLoading
                              ? 'Caricamento dispositivi...'
                              : 'Nessun dispositivo trovato',
                          style: TextStyle(
                            fontSize: 18,
                            color: Colors.grey.shade600,
                          ),
                        ),
                        if (!_isLoading) ...[
                          const SizedBox(height: 16),
                          FilledButton.icon(
                            onPressed: _fetchDevices,
                            icon: const Icon(Icons.refresh),
                            label: const Text('Riprova'),
                          ),
                        ],
                      ],
                    ),
                  )
                : Row(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      // Left: Device list
                      SizedBox(
                        width: 320,
                        child: ListView.builder(
                          itemCount: _devices.length,
                          itemBuilder: (ctx, i) {
                            final dev = _devices[i];
                            final name =
                                dev['deviceName'] ??
                                dev['name'] ??
                                'Dispositivo ${i + 1}';
                            final state =
                                dev['state'] ?? dev['status'] ?? 'Sconosciuto';
                            final isSelected = _selectedIndex == i;
                            return Card(
                              color: isSelected
                                  ? Theme.of(
                                      context,
                                    ).colorScheme.primary.withOpacity(0.1)
                                  : null,
                              shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(12),
                                side: isSelected
                                    ? BorderSide(
                                        color: Theme.of(
                                          context,
                                        ).colorScheme.primary,
                                        width: 2,
                                      )
                                    : BorderSide.none,
                              ),
                              child: ListTile(
                                leading: Container(
                                  width: 44,
                                  height: 44,
                                  decoration: BoxDecoration(
                                    color: _stateColor(state).withOpacity(0.15),
                                    borderRadius: BorderRadius.circular(10),
                                  ),
                                  child: Icon(
                                    _deviceIcon(name),
                                    color: _stateColor(state),
                                    size: 24,
                                  ),
                                ),
                                title: Text(
                                  name,
                                  style: const TextStyle(
                                    fontWeight: FontWeight.bold,
                                    fontSize: 15,
                                  ),
                                ),
                                subtitle: Row(
                                  children: [
                                    Container(
                                      width: 8,
                                      height: 8,
                                      decoration: BoxDecoration(
                                        shape: BoxShape.circle,
                                        color: _stateColor(state),
                                      ),
                                    ),
                                    const SizedBox(width: 6),
                                    Text(
                                      state,
                                      style: TextStyle(
                                        color: _stateColor(state),
                                        fontSize: 13,
                                      ),
                                    ),
                                  ],
                                ),
                                onTap: () => setState(() => _selectedIndex = i),
                              ),
                            );
                          },
                        ),
                      ),
                      const SizedBox(width: 24),
                      // Right: Device detail
                      Expanded(
                        child:
                            _selectedIndex != null &&
                                _selectedIndex! < _devices.length
                            ? _buildDeviceDetail(_devices[_selectedIndex!])
                            : Center(
                                child: Column(
                                  mainAxisSize: MainAxisSize.min,
                                  children: [
                                    Icon(
                                      Icons.touch_app,
                                      size: 56,
                                      color: Colors.grey.shade400,
                                    ),
                                    const SizedBox(height: 12),
                                    Text(
                                      'Seleziona un dispositivo per i dettagli',
                                      style: TextStyle(
                                        fontSize: 16,
                                        color: Colors.grey.shade600,
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                      ),
                    ],
                  ),
          ),
        ],
      ),
    );
  }

  Widget _buildDeviceDetail(Map<String, dynamic> dev) {
    final name = dev['deviceName'] ?? dev['name'] ?? 'N/D';
    final state = dev['state'] ?? dev['status'] ?? 'Sconosciuto';
    final info = dev['deviceInfo'] as Map<String, dynamic>? ?? {};
    final errorMsg = dev['errorMessage'] ?? dev['error'];
    final warningMsg = dev['warningMessage'] ?? dev['warning'];

    // Gather all info fields
    final Map<String, String> infoFields = {};
    infoFields['Nome'] = name;
    infoFields['Stato'] = state;
    if (info['serialNumber'] != null)
      infoFields['Numero Seriale'] = '${info['serialNumber']}';
    if (info['firmwareRevision'] != null)
      infoFields['Firmware'] = '${info['firmwareRevision']}';
    if (info['softwareRevision'] != null)
      infoFields['Software'] = '${info['softwareRevision']}';
    if (info['hardwareRevision'] != null)
      infoFields['Hardware Rev.'] = '${info['hardwareRevision']}';
    if (info['manufacturer'] != null)
      infoFields['Produttore'] = '${info['manufacturer']}';
    if (info['model'] != null) infoFields['Modello'] = '${info['model']}';
    if (info['type'] != null) infoFields['Tipo'] = '${info['type']}';
    if (dev['configVersion'] != null)
      infoFields['Config'] = '${dev['configVersion']}';
    if (dev['id'] != null) infoFields['ID'] = '${dev['id']}';

    // Add remaining info fields not already captured
    for (final entry in info.entries) {
      final key = entry.key;
      if (![
        'serialNumber',
        'firmwareRevision',
        'softwareRevision',
        'hardwareRevision',
        'manufacturer',
        'model',
        'type',
      ].contains(key)) {
        infoFields[key] = '${entry.value}';
      }
    }

    // Counters
    final counters = dev['counters'] as Map<String, dynamic>? ?? {};

    return SingleChildScrollView(
      child: Card(
        child: Padding(
          padding: const EdgeInsets.all(28.0),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Header
              Row(
                children: [
                  Container(
                    width: 56,
                    height: 56,
                    decoration: BoxDecoration(
                      color: _stateColor(state).withOpacity(0.15),
                      borderRadius: BorderRadius.circular(14),
                      border: Border.all(
                        color: _stateColor(state).withOpacity(0.4),
                      ),
                    ),
                    child: Icon(
                      _deviceIcon(name),
                      color: _stateColor(state),
                      size: 30,
                    ),
                  ),
                  const SizedBox(width: 16),
                  Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        name,
                        style: const TextStyle(
                          fontSize: 22,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                      const SizedBox(height: 4),
                      Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 3,
                        ),
                        decoration: BoxDecoration(
                          color: _stateColor(state).withOpacity(0.15),
                          borderRadius: BorderRadius.circular(12),
                        ),
                        child: Text(
                          state,
                          style: TextStyle(
                            color: _stateColor(state),
                            fontWeight: FontWeight.w600,
                            fontSize: 13,
                          ),
                        ),
                      ),
                    ],
                  ),
                ],
              ),

              // Error banner
              if (errorMsg != null) ...[
                const SizedBox(height: 16),
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.all(14),
                  decoration: BoxDecoration(
                    color: Colors.red.shade50,
                    borderRadius: BorderRadius.circular(10),
                    border: Border.all(color: Colors.red.shade300),
                  ),
                  child: Row(
                    children: [
                      Icon(
                        Icons.error_outline,
                        color: Colors.red.shade700,
                        size: 20,
                      ),
                      const SizedBox(width: 10),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              'Errore Dispositivo',
                              style: TextStyle(
                                fontWeight: FontWeight.bold,
                                color: Colors.red.shade700,
                                fontSize: 14,
                              ),
                            ),
                            const SizedBox(height: 4),
                            Text(
                              '$errorMsg',
                              style: TextStyle(
                                color: Colors.red.shade900,
                                fontSize: 13,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              ],

              // Warning banner
              if (warningMsg != null) ...[
                const SizedBox(height: 16),
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.all(14),
                  decoration: BoxDecoration(
                    color: Colors.orange.shade50,
                    borderRadius: BorderRadius.circular(10),
                    border: Border.all(color: Colors.orange.shade300),
                  ),
                  child: Row(
                    children: [
                      Icon(
                        Icons.warning_amber,
                        color: Colors.orange.shade700,
                        size: 20,
                      ),
                      const SizedBox(width: 10),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              'Avviso Dispositivo',
                              style: TextStyle(
                                fontWeight: FontWeight.bold,
                                color: Colors.orange.shade700,
                                fontSize: 14,
                              ),
                            ),
                            const SizedBox(height: 4),
                            Text(
                              '$warningMsg',
                              style: TextStyle(
                                color: Colors.orange.shade900,
                                fontSize: 13,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              ],

              const SizedBox(height: 24),
              // Info table
              const Text(
                'Informazioni Dispositivo',
                style: TextStyle(fontSize: 18, fontWeight: FontWeight.w600),
              ),
              const Divider(height: 20),
              ...infoFields.entries.map(
                (e) => Padding(
                  padding: const EdgeInsets.symmetric(vertical: 5),
                  child: Row(
                    children: [
                      SizedBox(
                        width: 160,
                        child: Text(
                          e.key,
                          style: const TextStyle(
                            fontSize: 14,
                            color: Colors.grey,
                            fontWeight: FontWeight.w500,
                          ),
                        ),
                      ),
                      Expanded(
                        child: Text(
                          e.value,
                          style: const TextStyle(fontSize: 14),
                        ),
                      ),
                    ],
                  ),
                ),
              ),

              // Counters
              if (counters.isNotEmpty) ...[
                const SizedBox(height: 24),
                const Text(
                  'Contatori',
                  style: TextStyle(fontSize: 18, fontWeight: FontWeight.w600),
                ),
                const Divider(height: 20),
                ...counters.entries.map(
                  (e) => Padding(
                    padding: const EdgeInsets.symmetric(vertical: 5),
                    child: Row(
                      children: [
                        SizedBox(
                          width: 160,
                          child: Text(
                            e.key,
                            style: const TextStyle(
                              fontSize: 14,
                              color: Colors.grey,
                              fontWeight: FontWeight.w500,
                            ),
                          ),
                        ),
                        Expanded(
                          child: Text(
                            '${e.value}',
                            style: const TextStyle(fontSize: 14),
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
              ],

              // Raw JSON section for any additional unstructured data
              const SizedBox(height: 24),
              ExpansionTile(
                title: const Text(
                  'Dati Grezzi (JSON)',
                  style: TextStyle(fontSize: 14, fontWeight: FontWeight.w500),
                ),
                tilePadding: EdgeInsets.zero,
                childrenPadding: const EdgeInsets.only(top: 8),
                children: [
                  Container(
                    width: double.infinity,
                    padding: const EdgeInsets.all(16),
                    decoration: BoxDecoration(
                      color: const Color(0xFF1E1E1E),
                      borderRadius: BorderRadius.circular(10),
                    ),
                    child: SelectableText(
                      const JsonEncoder.withIndent('  ').convert(dev),
                      style: const TextStyle(
                        color: Colors.greenAccent,
                        fontFamily: 'monospace',
                        fontSize: 12,
                      ),
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

/// ---------------------------------------------------------------------
/// TAB 4: DIAGNOSTICS & SYSTEM MESSAGES
/// ---------------------------------------------------------------------
class DiagnosticsTab extends StatefulWidget {
  const DiagnosticsTab({Key? key}) : super(key: key);
  @override
  State<DiagnosticsTab> createState() => _DiagnosticsTabState();
}

class _DiagnosticsTabState extends State<DiagnosticsTab> {
  List<dynamic> _devices = [];
  Map<String, dynamic>? _messages;

  @override
  void initState() {
    super.initState();
    _fetchDiagnostics();
  }

  Future<void> _fetchDiagnostics() async {
    try {
      final devices = await cpiApi.getDevices();
      final msgs = await cpiApi.getSystemMessages();
      setState(() {
        _devices = devices;
        _messages = msgs;
      });
    } catch (e) {
      debugPrint('Diag Error: $e');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.all(32.0),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(
                  mainAxisAlignment: MainAxisAlignment.spaceBetween,
                  children: [
                    const Text(
                      'Hardware Collegato',
                      style: TextStyle(
                        fontSize: 24,
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                    IconButton(
                      onPressed: _fetchDiagnostics,
                      icon: const Icon(Icons.refresh),
                    ),
                  ],
                ),
                const Divider(),
                Expanded(
                  child: ListView.builder(
                    itemCount: _devices.length,
                    itemBuilder: (c, i) {
                      final dev = _devices[i];
                      final state = dev['state'] ?? 'Sconosciuto';
                      final hasError =
                          dev['errorMessage'] != null || dev['error'] != null;
                      final hasWarning =
                          dev['warningMessage'] != null ||
                          dev['warning'] != null;
                      return Card(
                        margin: const EdgeInsets.only(bottom: 12),
                        child: ExpansionTile(
                          leading: Icon(
                            Icons.memory,
                            size: 36,
                            color: hasError
                                ? Colors.red
                                : (hasWarning
                                      ? Colors.orange
                                      : (state == 'Idle'
                                            ? Colors.green
                                            : Colors.grey)),
                          ),
                          title: Text(
                            '${dev['deviceName'] ?? 'Dispositivo'} - $state',
                            style: const TextStyle(fontWeight: FontWeight.bold),
                          ),
                          subtitle: Text(
                            'SN: ${dev['deviceInfo']?['serialNumber'] ?? 'N/D'} | FW: ${dev['deviceInfo']?['firmwareRevision'] ?? 'N/D'}',
                          ),
                          children: [
                            if (hasError)
                              Container(
                                width: double.infinity,
                                margin: const EdgeInsets.symmetric(
                                  horizontal: 16,
                                  vertical: 4,
                                ),
                                padding: const EdgeInsets.all(10),
                                decoration: BoxDecoration(
                                  color: Colors.red.shade50,
                                  borderRadius: BorderRadius.circular(8),
                                  border: Border.all(
                                    color: Colors.red.shade300,
                                  ),
                                ),
                                child: Row(
                                  children: [
                                    Icon(
                                      Icons.error_outline,
                                      color: Colors.red.shade700,
                                      size: 18,
                                    ),
                                    const SizedBox(width: 8),
                                    Expanded(
                                      child: Text(
                                        '${dev['errorMessage'] ?? dev['error']}',
                                        style: TextStyle(
                                          color: Colors.red.shade900,
                                          fontSize: 13,
                                        ),
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                            if (hasWarning)
                              Container(
                                width: double.infinity,
                                margin: const EdgeInsets.symmetric(
                                  horizontal: 16,
                                  vertical: 4,
                                ),
                                padding: const EdgeInsets.all(10),
                                decoration: BoxDecoration(
                                  color: Colors.orange.shade50,
                                  borderRadius: BorderRadius.circular(8),
                                  border: Border.all(
                                    color: Colors.orange.shade300,
                                  ),
                                ),
                                child: Row(
                                  children: [
                                    Icon(
                                      Icons.warning_amber,
                                      color: Colors.orange.shade700,
                                      size: 18,
                                    ),
                                    const SizedBox(width: 8),
                                    Expanded(
                                      child: Text(
                                        '${dev['warningMessage'] ?? dev['warning']}',
                                        style: TextStyle(
                                          color: Colors.orange.shade900,
                                          fontSize: 13,
                                        ),
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                            Padding(
                              padding: const EdgeInsets.all(16),
                              child: Text(
                                const JsonEncoder.withIndent('  ').convert(dev),
                                style: const TextStyle(
                                  fontFamily: 'monospace',
                                  fontSize: 12,
                                ),
                              ),
                            ),
                          ],
                        ),
                      );
                    },
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(width: 32),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Text(
                  'Log di Sistema e Avvisi',
                  style: TextStyle(fontSize: 24, fontWeight: FontWeight.bold),
                ),
                const Divider(),
                Expanded(
                  child: Container(
                    width: double.infinity,
                    padding: const EdgeInsets.all(24),
                    decoration: BoxDecoration(
                      color: const Color(0xFF1E1E1E),
                      borderRadius: BorderRadius.circular(16),
                    ),
                    child: SelectableText(
                      _messages != null
                          ? const JsonEncoder.withIndent(
                              '  ',
                            ).convert(_messages)
                          : 'Caricamento o nessun messaggio...',
                      style: const TextStyle(
                        color: Colors.greenAccent,
                        fontFamily: 'monospace',
                        fontSize: 14,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

/// ---------------------------------------------------------------------
/// TAB 5: SHIFT / SESSION MANAGEMENT
/// ---------------------------------------------------------------------
class SessionsTab extends StatefulWidget {
  const SessionsTab({Key? key}) : super(key: key);
  @override
  State<SessionsTab> createState() => _SessionsTabState();
}

class _SessionsTabState extends State<SessionsTab> {
  Map<String, dynamic>? _currentSession;
  bool _isLoading = false;

  @override
  void initState() {
    super.initState();
    _loadSession();
  }

  Future<void> _loadSession() async {
    final session = await cpiApi.getCurrentSession();
    setState(() => _currentSession = session);
  }

  Future<void> _startNewShift() async {
    setState(() => _isLoading = true);
    final success = await cpiApi.startNewSession();
    await _loadSession();
    setState(() => _isLoading = false);

    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            success
