class ExchangeRatesTab extends StatefulWidget {
  const ExchangeRatesTab({Key? key}) : super(key: key);
  @override
  State<ExchangeRatesTab> createState() => _ExchangeRatesTabState();
}

class _ExchangeRatesTabState extends State<ExchangeRatesTab> {
  List<dynamic> _rates = [];

  @override
  void initState() {
    super.initState();
    _fetchRates();
  }

  Future<void> _fetchRates() async {
    try {
      final rates = await cpiApi.getExchangeRates();
      setState(() => _rates = rates);
    } catch (e) {
      debugPrint('Rates Error: $e');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.all(32.0),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              const Text(
                'Tassi di Cambio Hardware',
                style: TextStyle(fontSize: 28, fontWeight: FontWeight.bold),
              ),
              IconButton(
                onPressed: _fetchRates,
                icon: const Icon(Icons.refresh),
              ),
            ],
          ),
          const Divider(),
          const SizedBox(height: 16),
          Expanded(
            child: _rates.isEmpty
                ? const Center(
                    child: Text(
                      'Nessun tasso esterno configurato.',
                      style: TextStyle(fontSize: 18, color: Colors.grey),
                    ),
                  )
                : ListView.builder(
                    itemCount: _rates.length,
                    itemBuilder: (c, i) {
                      final rate = _rates[i];
                      return Card(
                        child: ListTile(
                          leading: const Icon(
                            Icons.currency_exchange,
                            size: 32,
                          ),
                          title: Text(
                            '${rate['fromCurrency']} ➔ ${rate['toCurrency']}',
                            style: const TextStyle(
                              fontSize: 20,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                          trailing: Text(
                            'Tasso: ${rate['exchangeRate']}',
                            style: const TextStyle(fontSize: 20),
                          ),
                        ),
                      );
                    },
                  ),
          ),
        ],
      ),
    );
  }
}

/// ---------------------------------------------------------------------
/// 5. UNIVERSAL TRANSACTION MODAL (Real-time Feedback & Polling)
/// Handles standard transactions, Accepts, and Hardware level float downs.
/// Includes support for Split Payments by halting via 'End' API.
/// ---------------------------------------------------------------------
class CpiTransactionModal extends StatefulWidget {
  final String transactionType;
  final double amount;
  final String currencyCode;

  const CpiTransactionModal({
    Key? key,
    required this.transactionType,
    required this.amount,
    required this.currencyCode,
  }) : super(key: key);

  @override
  State<CpiTransactionModal> createState() => _CpiTransactionModalState();
}

class _CpiTransactionModalState extends State<CpiTransactionModal> {
  String? _transactionId;
  String _status = 'Inizializzazione dispositivo...';
  double _totalAccepted = 0.0;
  double _totalDispensed = 0.0;
  Timer? _pollingTimer;
  bool _isFinished = false;
  String? _errorDetails;
  // Smart dispense: split into multiple sub-transactions
  bool _isSmartDispensing = false;
  int _smartDispenseTotal = 0;
  double _smartTotalDispensed = 0.0;

  @override
  void initState() {
    super.initState();
    _initiateTransaction();
  }

  bool get _isDispenseType =>
      widget.transactionType == 'Refund' ||
      widget.transactionType == 'Dispense';

  Future<void> _initiateTransaction() async {
    try {
      _transactionId = await cpiApi.startTransaction(
        widget.transactionType,
        widget.amount,
        widget.currencyCode,
      );
      setState(() => _status = 'Elaborazione hardware...');
      _startPolling();
    } catch (e) {
      // If dispense fails immediately, attempt smart denomination split
      if (_isDispenseType && !_isSmartDispensing) {
        await _attemptSmartDispense();
      } else {
        setState(() {
          _status = 'Errore Avvio';
          _errorDetails = '$e';
          _isFinished = true;
        });
      }
    }
  }

  /// When a Dispense fails with InsufficientChange, queries device inventory
  /// and attempts to split into multiple smaller dispense transactions using
  /// available denominations that sum to the requested amount.
  Future<void> _attemptSmartDispense() async {
    setState(() {
      _status = 'Verifica erogazione alternativa...';
      _errorDetails = null;
    });

    try {
      final inventory = await cpiApi.getDispensableInventory();
      final targetCents = (widget.amount * 100).round();
      final breakdown = DenominationCalculator.calculateBreakdown(
        targetCents,
        inventory,
      );

      if (breakdown == null || breakdown.isEmpty) {
        setState(() {
          _status = 'Resto Insufficiente nel Sistema!';
          _errorDetails =
              'Impossibile erogare ${widget.currencyCode} ${widget.amount.toStringAsFixed(2)} '
              'con le denominazioni disponibili.';
          _isFinished = true;
        });
        return;
      }

      // Start smart dispense sequence
      final dispenseSteps = <double>[];
      for (final entry in breakdown.entries) {
        final denomEur = entry.key / 100.0;
        for (int i = 0; i < entry.value; i++) {
          dispenseSteps.add(denomEur);
        }
      }

      setState(() {
        _isSmartDispensing = true;
        _smartDispenseTotal = dispenseSteps.length;
        _smartTotalDispensed = 0.0;
        _status =
            'Erogazione suddivisa: ${DenominationCalculator.formatBreakdown(breakdown)}';
      });

      // Execute each sub-dispense sequentially
      for (int i = 0; i < dispenseSteps.length; i++) {
        if (!mounted) return;
        final stepAmount = dispenseSteps[i];
        setState(() {
          _status =
              'Erogazione ${i + 1}/$_smartDispenseTotal: '
              '${widget.currencyCode} ${stepAmount.toStringAsFixed(2)}';
        });

        try {
          final subTxId = await cpiApi.startTransaction(
            widget.transactionType,
            stepAmount,
            widget.currencyCode,
          );
          // Wait for sub-transaction to complete
          await _waitForTransactionCompletion(subTxId);
          _smartTotalDispensed += stepAmount;
          if (mounted) {
            setState(() {
              _totalDispensed = _smartTotalDispensed;
            });
          }
        } catch (e) {
          if (mounted) {
            setState(() {
              _status = 'Errore durante erogazione suddivisa';
              _errorDetails =
                  'Erogato ${widget.currencyCode} ${_smartTotalDispensed.toStringAsFixed(2)} '
                  'di ${widget.currencyCode} ${widget.amount.toStringAsFixed(2)}. '
                  'Errore passo ${i + 1}: $e';
              _isFinished = true;
            });
          }
          return;
        }
      }

      // All sub-transactions completed
      if (mounted) {
        setState(() {
          _status = 'Transazione Completata!';
          _totalDispensed = _smartTotalDispensed;
          _isFinished = true;
        });
      }
    } catch (e) {
      setState(() {
        _status = 'Resto Insufficiente nel Sistema!';
        _errorDetails = '$e';
        _isFinished = true;
      });
    }
  }

  /// Waits for a sub-transaction to reach a terminal state by polling.
  Future<void> _waitForTransactionCompletion(String transactionId) async {
    const maxAttempts = 60; // 60 seconds max per sub-transaction
    for (int attempt = 0; attempt < maxAttempts; attempt++) {
      await Future.delayed(const Duration(seconds: 1));
      final details = await cpiApi.getTransactionDetails(transactionId);
      final apiStatus = details['status'] ?? 'Unknown';

      if (apiStatus == 'CompletedSuccess') return;

      if ([
        'Cancelled',
        'DeviceError',
        'InsufficientChange',
        'NotStartedInsufficientChange',
        'NotStartedBusy',
      ].contains(apiStatus)) {
        throw Exception('Sub-transazione fallita: $apiStatus');
      }
    }
    throw Exception('Timeout sub-transazione');
  }

  void _startPolling() {
    _pollingTimer = Timer.periodic(const Duration(seconds: 1), (timer) async {
      if (_transactionId == null) return;
      try {
        final details = await cpiApi.getTransactionDetails(_transactionId!);
        final apiStatus = details['status'] ?? 'Unknown';

        // CPI returns amounts in cents. Scale to standard double format natively
        final rawAccepted = details['totalAccepted'] ?? 0;
        final rawDispensed = details['totalDispensed'] ?? 0;

        if (mounted) {
          setState(() {
            _totalAccepted = rawAccepted / 100.0;
            _totalDispensed = rawDispensed / 100.0;
            _status = _formatApiStatus(apiStatus);
            // Capture error details from response
            if (details['errorMessage'] != null) {
              _errorDetails = '${details['errorMessage']}';
            } else if (details['error'] != null) {
              _errorDetails = '${details['error']}';
            } else if (details['warningMessage'] != null ||
                details['warning'] != null) {
              _errorDetails =
                  '${details['warningMessage'] ?? details['warning']}';
            }
          });
        }

        // Terminal device states
        if ([
          'CompletedSuccess',
          'Cancelled',
          'DeviceError',
          'NotStartedBusy',
          'NotStarted',
        ].contains(apiStatus)) {
          timer.cancel();
          setState(() => _isFinished = true);
        }

        // InsufficientChange: attempt smart denomination split before giving up
        if ([
          'InsufficientChange',
          'NotStartedInsufficientChange',
        ].contains(apiStatus)) {
          timer.cancel();
          if (_isDispenseType && !_isSmartDispensing) {
            _attemptSmartDispense();
          } else {
            setState(() => _isFinished = true);
          }
        }
      } catch (e) {
        debugPrint('Polling Error: $e');
      }
    });
  }

  String _formatApiStatus(String apiStatus) {
    switch (apiStatus) {
      case 'InProgress':
        return widget.transactionType == 'Accept'
            ? 'Accettazione deposito continuo...'
            : 'In attesa inserimento contanti...';
      case 'CompletedSuccess':
        return 'Transazione Completata!';
      case 'Cancelled':
        return 'Transazione Annullata e Depositata.';
      case 'InsufficientChange':
        return 'Resto Insufficiente nel Sistema!';
      case 'NotStartedInsufficientChange':
        return 'Bloccato: Impossibile erogare resto.';
      case 'NotStartedBusy':
        return 'Errore Hardware / Occupato: Controllare connessione.';
      case 'NotStarted':
        return 'Avvio Controller Hardware...';
      case 'DeviceError':
        return 'Inceppamento o Errore Hardware Rilevato.';
      default:
        return apiStatus;
    }
  }

  Future<void> _cancelFull() async {
    if (_transactionId != null) {
      setState(() => _status = 'Annullamento e deposito contanti...');
      await cpiApi.cancelTransaction(_transactionId!);
    }
  }

  Future<void> _splitPaymentEnd() async {
    if (_transactionId != null) {
      setState(() => _status = 'Fine fase contanti e salvataggio...');
      // Calls /action/end to keep currently inserted cash (Split payment functionality)
      await cpiApi.endTransaction(_transactionId!);
    }
  }

  @override
  void dispose() {
    _pollingTimer?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return PopScope(
      canPop: true,
      onPopInvokedWithResult: (didPop, result) {
        if (didPop && !_isFinished && _transactionId != null) {
          _cancelFull();
        }
      },
      child: Dialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),
        child: Container(
          width: 700,
          padding: const EdgeInsets.all(48),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Text(
                'Operazione: ${_localizeTransactionType(widget.transactionType)}',
                style: const TextStyle(
                  fontSize: 20,
                  color: Colors.grey,
                  letterSpacing: 1.2,
                ),
              ),
              const SizedBox(height: 16),
              Text(
                _status,
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontSize: 36,
                  fontWeight: FontWeight.bold,
                  color: Theme.of(context).colorScheme.primary,
                ),
              ),

              // Error/Warning details banner
              if (_errorDetails != null) ...[
                Container(
                  width: double.infinity,
                  margin: const EdgeInsets.only(top: 12, bottom: 4),
                  padding: const EdgeInsets.all(14),
                  decoration: BoxDecoration(
                    color: _isFinished
                        ? Colors.red.shade50
                        : Colors.orange.shade50,
                    borderRadius: BorderRadius.circular(10),
                    border: Border.all(
                      color: _isFinished
                          ? Colors.red.shade300
                          : Colors.orange.shade300,
                    ),
                  ),
                  child: Row(
                    children: [
                      Icon(
                        _isFinished ? Icons.error_outline : Icons.warning_amber,
                        color: _isFinished
                            ? Colors.red.shade700
                            : Colors.orange.shade700,
                        size: 20,
                      ),
                      const SizedBox(width: 10),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              _isFinished ? 'Dettagli Errore' : 'Avviso',
                              style: TextStyle(
                                fontWeight: FontWeight.bold,
                                color: _isFinished
                                    ? Colors.red.shade700
                                    : Colors.orange.shade700,
                                fontSize: 13,
                              ),
                            ),
                            const SizedBox(height: 4),
                            SelectableText(
                              _errorDetails!,
                              style: TextStyle(
                                color: _isFinished
                                    ? Colors.red.shade900
                                    : Colors.orange.shade900,
                                fontSize: 13,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              ],

              const SizedBox(height: 24),

              Row(
                mainAxisAlignment: MainAxisAlignment.spaceEvenly,
                children: [
                  if (widget.amount > 0) _buildStat('Dovuto', widget.amount),
                  _buildStat(
                    'Accettato',
                    _totalAccepted,
                    isHighlight: _totalAccepted > 0,
                  ),
                  _buildStat(
                    'Erogato',
                    _totalDispensed,
                    isHighlight: _totalDispensed > 0,
                  ),
                ],
              ),

              const SizedBox(height: 48),
              if (!_isFinished)
                const LinearProgressIndicator(
                  minHeight: 8,
                  borderRadius: BorderRadius.all(Radius.circular(4)),
                ),
              const SizedBox(height: 48),

              if (_isFinished)
                SizedBox(
                  width: double.infinity,
                  height: 70,
                  child: FilledButton(
                    onPressed: () => Navigator.pop(context),
                    child: const Text('CHIUDI', style: TextStyle(fontSize: 22)),
                  ),
                )
              else if (widget.transactionType == 'Accept')
                SizedBox(
                  width: double.infinity,
                  height: 70,
                  child: FilledButton(
                    style: FilledButton.styleFrom(
                      backgroundColor: Theme.of(context).colorScheme.secondary,
                    ),
                    onPressed: _splitPaymentEnd,
                    child: const Text(
                      'TERMINA ACCETTAZIONE',
                      style: TextStyle(fontSize: 22),
                    ),
                  ),
                )
              else
                Row(
                  children: [
                    Expanded(
                      child: SizedBox(
                        height: 70,
                        child: OutlinedButton(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: Colors.red.shade700,
                            side: BorderSide(
                              color: Colors.red.shade700,
                              width: 2,
                            ),
                          ),
                          onPressed: _cancelFull,
                          child: const Text(
                            'ANNULLA (RESTITUISCI)',
                            style: TextStyle(fontSize: 18),
                          ),
                        ),
                      ),
                    ),
                    const SizedBox(width: 16),
                    Expanded(
                      child: SizedBox(
                        height: 70,
                        child: FilledButton(
                          style: FilledButton.styleFrom(
                            backgroundColor: Theme.of(
                              context,
                            ).colorScheme.secondary,
                          ),
                          // Split Payment: Ends transaction but keeps the money currently accepted
                          onPressed: _splitPaymentEnd,
                          child: const Text(
                            'PAGAMENTO DIVISO',
                            style: TextStyle(fontSize: 18),
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
            ],
          ),
        ),
      ), // end Dialog
    ); // end PopScope
  }

  Widget _buildStat(String label, double value, {bool isHighlight = false}) {
    return Column(
      children: [
        Text(label, style: const TextStyle(fontSize: 20, color: Colors.grey)),
        const SizedBox(height: 12),
        Text(
          '${widget.currencyCode} ${value.toStringAsFixed(2)}',
          style: TextStyle(
            fontSize: 40,
            fontWeight: FontWeight.bold,
            color: isHighlight ? Colors.green.shade700 : Colors.black87,
          ),
        ),
      ],
    );
  }

  String _localizeTransactionType(String type) {
    switch (type) {
      case 'Payment':
        return 'Pagamento';
      case 'Refund':
        return 'Rimborso';
      case 'Accept':
        return 'Deposito Continuo';
      case 'FloatToCashBox':
        return 'Float verso Cassaforte';
      case 'FloatToDispense':
        return 'Float verso Erogazione';
      case 'EmptyToCashBox':
        return 'Svuota verso Cassaforte';
      case 'EmptyToDispense':
        return 'Svuota verso Erogazione';
      default:
        return type;
    }
  }
}
